import 'package:flutter/widgets.dart';

class CounterLabel extends StatelessWidget {
  CounterLabel({super.key, required this.initial});

  int count;

  @override
  Widget build(BuildContext context) {
    count += 1;
    return Text('$count');
  }
}

import 'package:flutter/widgets.dart';

class CounterLabel extends StatelessWidget {
  const CounterLabel({super.key, required this.count});

  final int count;

  @override
  Widget build(BuildContext context) {
    return Text('$count');
  }
}

import 'package:flutter/widgets.dart';

class CounterLabel extends StatefulWidget {
  const CounterLabel({super.key});

  @override
  State<CounterLabel> createState() => _CounterLabelState();
}

class _CounterLabelState extends State<CounterLabel> {
  int _count = 0;

  @override
  Widget build(BuildContext context) {
    return Text('${_count++}');
  }
}
